SELECT COUNT(*)
FROM orders
WHERE member_no = #{memberNo}



    AND order_date >= #{startDate}



    AND order_date <= #{endDate}

SELECT point
FROM member
WHERE member_no = #{memberNo}

SELECT COUNT(*)
FROM qna
WHERE member_no = #{memberNo}

SELECT COUNT(*)
FROM member_point
WHERE member_no = #{memberNo}

SELECT r.review_no AS reviewNo, r.rating, r.content, r.reg_date AS regDate, oi.product_name AS productName, oi.product_image AS imagePath
FROM product_review r INNER JOIN order_item oi ON r.order_item_no = oi.order_item_no
WHERE r.member_no = #{memberNo}
ORDER BY r.reg_date DESC
LIMIT #{start}, #{size}

SELECT COUNT(*)
FROM product_review
WHERE member_no = #{memberNo}

SELECT product_no
FROM order_item
WHERE order_item_no = #{orderItemNo}

SELECT ci.issue_no AS issueNo, ci.issue_code AS issueCode, ci.coupon_no AS couponNo, ci.member_no AS memberNo, ci.order_no AS orderNo, ci.status AS status, ci.used_date AS usedDate, ci.issue_date AS issueDate,
c.coupon_code AS couponCode, c.coupon_type AS couponType, c.coupon_name AS couponName, c.benefit_type AS benefitType, c.benefit_value AS benefitValue, c.min_order_price AS minOrderPrice, c.max_discount_price AS maxDiscountPrice, c.start_date AS startDate, c.end_date AS endDate, c.caution AS caution
FROM coupon_issue ci INNER JOIN coupon c ON ci.coupon_no = c.coupon_no
WHERE ci.member_no = #{memberNo}
ORDER BY ci.issue_date DESC
LIMIT #{start}, #{size}

SELECT member_no AS memberNo, member_id AS memberId, name, birth, email, hp, zip, addr1, addr2
FROM member
WHERE member_no = #{memberNo}

mapper.update:
UPDATE member
SET email = #{email}, hp = #{hp}, zip = #{zip}, addr1 = #{addr1}, addr2 = #{addr2}
WHERE member_no = #{memberNo}
